import React from "react";
import { FOOTER_DATA } from "../data/siteData";
import Newsletter from "./Newsletter";

/**
 * Footer — full footer with newsletter, 4-column grid, and bottom bar.
 */
const Footer = () => {
  const { brand, description, email, location, copyright, tagline, columns } =
    FOOTER_DATA;

  return (
    <footer
      style={{
        background: "#f7f4ef",
        padding: "clamp(60px, 10vh, 120px) clamp(30px, 7vw, 90px) 50px",
        color: "#111",
      }}
    >
      {/* Newsletter strip */}
      <Newsletter />

      {/* 4-column grid */}
      <div
        style={{
          display: "grid",
          gridTemplateColumns: "repeat(auto-fit, minmax(200px, 1fr))",
          gap: "60px",
          marginBottom: "80px",
        }}
      >
        {/* Brand column */}
        <div>
          <h4
            style={{
              fontSize: "12px",
              textTransform: "uppercase",
              letterSpacing: "4px",
              marginBottom: "28px",
              color: "#777",
            }}
          >
            {brand}
          </h4>
          <p style={{ fontSize: "15px", lineHeight: 1.9, color: "#444" }}>
            {description}
          </p>
        </div>

        {/* Dynamic link columns */}
        {columns.map((col) => (
          <div key={col.heading}>
            <h4
              style={{
                fontSize: "12px",
                textTransform: "uppercase",
                letterSpacing: "4px",
                marginBottom: "28px",
                color: "#777",
              }}
            >
              {col.heading}
            </h4>
            <ul style={{ listStyle: "none" }}>
              {col.links.map(({ label, href, external }) => (
                <li key={label} style={{ marginBottom: "16px" }}>
                  <a
                    href={href}
                    className="footer-link"
                    target={external ? "_blank" : undefined}
                    rel={external ? "noopener noreferrer" : undefined}
                  >
                    {label}
                  </a>
                </li>
              ))}
            </ul>
          </div>
        ))}

        {/* Contact column */}
        <div>
          <h4
            style={{
              fontSize: "12px",
              textTransform: "uppercase",
              letterSpacing: "4px",
              marginBottom: "28px",
              color: "#777",
            }}
          >
            Contact
          </h4>
          <p style={{ fontSize: "15px", lineHeight: 1.9, color: "#444" }}>
            {email}
          </p>
          <p
            style={{
              fontSize: "15px",
              lineHeight: 1.9,
              color: "#444",
              marginTop: "18px",
              whiteSpace: "pre-line",
            }}
          >
            {location}
          </p>
        </div>
      </div>

      {/* Bottom bar */}
      <div
        style={{
          borderTop: "1px solid rgba(0,0,0,.08)",
          paddingTop: "32px",
          display: "flex",
          justifyContent: "space-between",
          alignItems: "center",
          fontSize: "11px",
          letterSpacing: "4px",
          textTransform: "uppercase",
          color: "#777",
          flexWrap: "wrap",
          gap: "14px",
        }}
      >
        <p>{copyright}</p>
        <p>{tagline}</p>
      </div>
    </footer>
  );
};

export default Footer;
